const { Inconvo } = require('@inconvoai/node');
const fs = require('fs');

async function main() {
  const client = new Inconvo();

  try {
    // Creating a conversation with context
    // The prompt says client.conversations.create, but in this SDK version it's under client.agents.conversations
    // and it requires the agent ID.
    const agentId = process.env.INCONVO_AGENT_ID;

    console.log("Creating conversation...");
    const conversation = await client.agents.conversations.create(agentId, {
      context: { store_id: 123 }
    });

    console.log("Sending message...");
    // The prompt says client.conversations.messages.create
    // In this SDK, it's client.agents.conversations.response.create
    const response = await client.agents.conversations.response.create(conversation.id, {
      agentId: agentId,
      message: "What are my orders?"
    });

    fs.writeFileSync('/home/user/inconvo-app/response.json', JSON.stringify(response, null, 2));
    console.log("Response saved to response.json");
  } catch (error) {
    console.error("Error:", error);
    process.exit(1);
  }
}

main();

